        "code": "\"use client\";\n\nimport { motion } from \"motion/react\";\nimport { ArrowUpRight, DollarSign, TrendingUp, Users } from \"lucide-react\";\nimport { cn } from \"@/lib/utils\";\n\n/**\n * REVENUE METRIC CARD (Right Top)\n * Features \"Total Revenue\" title, status pill, and high-fidelity currency display.\n */\nexport function RevenueMetricCard({ className }: { className?: string }) {\n  return (\n    <motion.div\n      whileHover={{ y: -5, transition: { duration: 0.2 } }}\n      className={cn(\n        \"flex flex-col gap-4 rounded-2xl border border-zinc-100 bg-white p-6 shadow-xl dark:border-zinc-800 dark:bg-zinc-950\",\n        className\n      )}\n    >\n      <div className=\"flex items-center justify-between\">\n        <span className=\"text-[13px] font-semibold text-zinc-500 uppercase tracking-wide\">Total Revenue</span>\n        <div className=\"flex size-6 items-center justify-center rounded-full bg-[#BFFF70]/10 text-[#54A000]\">\n           <ArrowUpRight className=\"size-3.5\" />\n        </div>\n      </div>\n      <div className=\"flex items-center gap-3\">\n        <div className=\"flex size-12 items-center justify-center rounded-full bg-[#BFFF70] text-[#03251E]\">\n          <DollarSign className=\"size-6\" />\n        </div>\n        <div className=\"flex flex-col\">\n          <span className=\"text-3xl font-bold tracking-tight text-zinc-900 dark:text-white\">4.32k</span>\n          <span className=\"text-[12px] font-medium text-emerald-600\">+12.5% from last month</span>\n        </div>\n      </div>\n    </motion.div>\n  );\n}\n\n/**\n * INCOME CHART CARD (Left Top)\n * Features \"Income & Expenses\" title and a stylized high-fidelity mockup chart.\n */\nexport function IncomeChartCard({ className }: { className?: string }) {\n  return (\n    <motion.div\n      whileHover={{ y: -5, transition: { duration: 0.2 } }}\n      className={cn(\n        \"flex flex-col gap-6 rounded-2xl border border-zinc-100 bg-white p-6 shadow-xl dark:border-zinc-800 dark:bg-zinc-950\",\n        \"w-[280px]\",\n        className\n      )}\n    >\n      <div className=\"flex items-center justify-between border-b border-zinc-50 pb-4 dark:border-zinc-900\">\n        <span className=\"text-[13px] font-bold text-zinc-900 dark:text-white\">Income & Expenses</span>\n        <button className=\"text-[12px] font-bold text-zinc-400 hover:text-zinc-600 transition-colors\">7 Days</button>\n      </div>\n\n      {/* Stylized Chart Mockup */}\n      <div className=\"relative h-32 w-full pt-4\">\n        {/* Mock Chart SVG */}\n        <svg className=\"h-full w-full\" viewBox=\"0 0 200 80\">\n          <path\n            d=\"M 10 70 Q 30 20, 50 60 T 90 20 T 130 50 T 170 10 T 190 40\"\n            fill=\"none\"\n            stroke=\"#03251E\"\n            strokeWidth=\"3.5\"\n            strokeLinecap=\"round\"\n            className=\"opacity-90 dark:stroke-emerald-400\"\n          />\n          <path\n            d=\"M 10 70 Q 30 20, 50 60 T 90 20 T 130 50 T 170 10 T 190 40 L 190 80 L 10 80 Z\"\n            fill=\"url(#chart-gradient)\"\n            className=\"opacity-10\"\n          />\n          <defs>\n            <linearGradient id=\"chart-gradient\" x1=\"0\" x2=\"0\" y1=\"0\" y2=\"1\">\n              <stop offset=\"0%\" stopColor=\"#BFFF70\" />\n              <stop offset=\"100%\" stopColor=\"transparent\" />\n            </linearGradient>\n          </defs>\n          <circle cx=\"170\" cy=\"10\" r=\"4\" fill=\"#BFFF70\" className=\"animate-pulse shadow-glow\" />\n        </svg>\n        \n        {/* Floating Tooltip */}\n        <div className=\"absolute top-0 right-4 rounded bg-[#BFFF70] px-2 py-1 text-[10px] font-bold text-[#03251E] shadow-sm\">\n          $2,890\n        </div>\n      </div>\n    </motion.div>\n  );\n}\n\n/**\n * BALANCE PROGRESS CARD (Right Bottom)\n * Features \"Balance\" title, numeric amount, and custom progress bar with Pine accent.\n */\nexport function BalanceProgressBarCard({ className }: { className?: string }) {\n  return (\n    <motion.div\n      whileHover={{ y: -5, transition: { duration: 0.2 } }}\n      className={cn(\n        \"flex flex-col gap-5 rounded-2xl border border-zinc-100 bg-white p-6 shadow-xl dark:border-zinc-800 dark:bg-zinc-950\",\n        \"w-[260px]\",\n        className\n      )}\n    >\n      <div className=\"flex items-center justify-between\">\n        <span className=\"text-[13px] font-bold text-zinc-900 dark:text-white\">Balance</span>\n        <span className=\"rounded-full bg-zinc-900 px-3 py-1 text-[10px] font-bold text-white uppercase tracking-wider\">Reserved</span>\n      </div>\n      <div className=\"flex flex-col gap-1\">\n        <span className=\"text-2xl font-black text-zinc-900 dark:text-white\">$60,124.00</span>\n        <div className=\"mt-2 flex items-center justify-between\">\n          <div className=\"flex items-center gap-1.5 text-[10px] font-black text-zinc-400 uppercase tracking-widest\">\n            <div className=\"size-1.5 rounded-full bg-[#BFFF70]\" />\n            Pine Account\n          </div>\n          <span className=\"text-[10px] font-black text-zinc-900 dark:text-emerald-400\">75%</span>\n        </div>\n        <div className=\"relative mt-1 h-1.5 w-full overflow-hidden rounded-full bg-zinc-50 dark:bg-zinc-900\">\n          <motion.div \n            initial={{ width: 0 }}\n            animate={{ width: \"75%\" }}\n            transition={{ duration: 1, delay: 0.5, ease: \"circOut\" }}\n            className=\"h-full bg-[#BFFF70] shadow-[0_0_10px_rgba(191,255,112,0.4)]\" \n          />\n        </div>\n      </div>\n    </motion.div>\n  );\n}\n\n/**\n * MEMBER GROWTH CARD (Left Bottom)\n * Features numeric metric, progress badge, and descriptive footer.\n */\nexport function MemberGrowthCard({ className }: { className?: string }) {\n  return (\n    <motion.div\n      whileHover={{ y: -5, transition: { duration: 0.2 } }}\n      className={cn(\n        \"flex flex-col gap-4 rounded-2xl border border-zinc-100 bg-white p-6 shadow-xl dark:border-zinc-800 dark:bg-zinc-950\",\n        className\n      )}\n    >\n      <div className=\"flex items-center gap-4\">\n        <div className=\"flex flex-col\">\n          <span className=\"text-3xl font-black text-zinc-900 dark:text-white\">75%</span>\n          <span className=\"text-[12px] font-medium text-zinc-500\">Member Growth</span>\n        </div>\n        <div className=\"flex h-12 items-center justify-center rounded-xl bg-zinc-900 px-4 text-white hover:bg-zinc-800 transition-colors cursor-pointer\">\n           <span className=\"text-[12px] font-bold\">Details</span>\n        </div>\n      </div>\n    </motion.div>\n  );\n}",
