        "code": "\"use client\";\nimport { ArrowRight } from \"lucide-react\";\nimport { cn } from \"@/lib/utils\";\n\nexport function Footer() {\n  return (\n    <footer className=\"border-t bg-[radial-gradient(35%_128px_at_50%_0%,theme(colors.white/8%),transparent)]\">\n      <div className=\"relative mx-auto max-w-5xl px-4\">\n        <div className=\"relative grid grid-cols-1 border-x md:grid-cols-4 md:divide-x\">\n          <div>\n            <SocialCard className=\"border-t-0\" href=\"#\" title=\"Facebook\" />\n            <LinksGroup\n              links={[\n                { title: \"Pricing\", href: \"#\" },\n                { title: \"Testimonials\", href: \"#\" },\n                { title: \"FAQs\", href: \"#\" },\n                { title: \"Contact Us\", href: \"#\" },\n                { title: \"Blog\", href: \"#\" },\n              ]}\n              title=\"About Us\"\n            />\n          </div>\n          <div>\n            <SocialCard href=\"#\" title=\"Youtube\" />\n            <LinksGroup\n              links={[\n                { title: \"Help Center\", href: \"#\" },\n                { title: \"Terms\", href: \"#\" },\n                { title: \"Privacy\", href: \"#\" },\n                { title: \"Security\", href: \"#\" },\n                { title: \"Cookie Policy\", href: \"#\" },\n              ]}\n              title=\"Support\"\n            />\n          </div>\n\n          <div>\n            <SocialCard href=\"#\" title=\"Twitter\" />\n            <LinksGroup\n              links={[\n                { title: \"Forum\", href: \"#\" },\n                { title: \"Events\", href: \"#\" },\n                { title: \"Partners\", href: \"#\" },\n                { title: \"Affiliates\", href: \"#\" },\n                { title: \"Career\", href: \"#\" },\n              ]}\n              title=\"Community\"\n            />\n          </div>\n          <div>\n            <SocialCard href=\"#\" title=\"Instagram\" />\n            <LinksGroup\n              links={[\n                { title: \"Investors\", href: \"#\" },\n                { title: \"Terms of Use\", href: \"#\" },\n                { title: \"Privacy Policy\", href: \"#\" },\n                { title: \"Cookie Policy\", href: \"#\" },\n                { title: \"Legal\", href: \"#\" },\n              ]}\n              title=\"Press\"\n            />\n          </div>\n        </div>\n      </div>\n      <div className=\"flex justify-center border-t p-3\">\n        <p className=\"text-muted-foreground text-xs\">\n          &copy; {new Date().getFullYear()} freddy, All rights reserved\n        </p>\n      </div>\n    </footer>\n  );\n}\n\ntype LinksGroupProps = {\n  title: string;\n  links: { title: string; href: string }[];\n};\nfunction LinksGroup({ title, links }: LinksGroupProps) {\n  return (\n    <div className=\"p-2\">\n      <h3 className=\"mt-2 mb-4 font-medium text-foreground/75 text-xs uppercase tracking-wider\">\n        {title}\n      </h3>\n      <ul>\n        {links.map((link) => (\n          <li key={link.title}>\n            <a\n              className=\"text-muted-foreground text-xs hover:text-foreground\"\n              href={link.href}\n            >\n              {link.title}\n            </a>\n          </li>\n        ))}\n      </ul>\n    </div>\n  );\n}\n\nfunction SocialCard({\n  title,\n  href,\n  className,\n}: {\n  title: string;\n  href: string;\n  className?: string;\n}) {\n  return (\n    <a\n      className={cn(\n        \"flex items-center justify-between border-y p-2 text-sm hover:bg-accent hover:text-accent-foreground md:border-t-0\",\n        className\n      )}\n      href={href}\n    >\n      <span className=\"font-medium\">{title}</span>\n      <ArrowRight className=\"h-4 w-4 transition-colors\" />\n    </a>\n  );\n}",
